sql:
SELECT user_name, job_title
FROM users
WHERE user_id IN (
    SELECT created_by_id
    FROM objectives
);

SELECT COUNT(objective_id)
FROM objectives
WHERE status = 'In Progress';

SELECT objective_description
FROM objectives
ORDER BY created_date DESC;

SELECT COUNT(objective_id) AS active_objectives_count
FROM objectives
WHERE status = 'Active' AND project_manager_id = 1;

external_knowledge:
; Created in 2023 means that the creation date falls between January 1st, 2023, and December 31st, 2023; 
; In progress refers to the current status of the objectives; 
; More than once by the same manager means that the objective appears more than once in the results, indicating it was created multiple times by the same project manager.
